chart.options:
chart: {
  height: 350,
  type: 'area'
},
dataLabels: {
  enabled: false
},
stroke: {
  curve: 'smooth'
},
title: {
  text: 'Renewable Energy Generation',
  align: 'left'
},
xaxis: {
  type: 'datetime',
  categories: ["2025-06-01", "2025-06-02", "2025-06-03", "2025-06-04", "2025-06-05", "2025-06-06", "2025-06-07", "2025-06-08", "2025-06-09", "2025-06-10", "2025-06-11", "2025-06-12", "2025-06-13", "2025-06-14"]
},
yaxis: {
  labels: {
    formatter: function (val) {
      return val + ' GWh'
    }
  }
},
tooltip: {
  x: {
    format: 'dd MMM yyyy'
  },
},
